mapper.select:
SELECT 
FROM t_eval_task t
JOIN t_eval_dataset d ON t.dataset_id = d.id
JOIN t_eval_dataset_version v ON t.dataset_version_id = v.id
WHERE t.is_deleted = 0

    AND t.status = #{status}

  AND (#{like} = '%%' OR t.task_name LIKE #{like})
ORDER BY ${orderColumn} ${orderDirection}
LIMIT #{size} OFFSET #{offset}

SELECT r.id AS id, r.task_item_id AS taskItemId, r.task_evaluator_id AS taskEvaluatorId, CASE WHEN te.evaluator_source = 'preset' THEN '' ELSE e.evaluator_name END AS evaluatorName, CASE WHEN te.evaluator_source = 'preset' THEN '' ELSE e.evaluator_type END AS evaluatorType, CASE WHEN te.evaluator_source = 'preset' THEN '预置' WHEN ev.version_no = 0 THEN '草稿' ELSE CONCAT('V', ev.version_no) END AS versionName, r.status AS status, r.score AS score, r.pass_result AS passResult, r.result_value AS resultValue, r.error_message AS errorMessage, r.started_at AS startedAt, r.finished_at AS finishedAt FROM t_eval_task_evaluator_result r JOIN t_eval_task_evaluator te ON r.task_evaluator_id = te.id LEFT JOIN t_eval_evaluator e ON te.evaluator_source = 'custom' AND te.evaluator_id = e.id LEFT JOIN t_eval_evaluator_version ev ON te.evaluator_version_id = ev.id WHERE r.task_item_id IN
#{taskItemId}
ORDER BY te.display_order ASC

SELECT r.id AS id, r.task_item_id AS taskItemId, r.task_tag_id AS taskTagId, tag.id AS tagId, tag.tag_name AS tagName, tag.tag_type AS tagType, r.status AS status, r.value_text AS valueText, r.value_number AS valueNumber, r.tag_option_id AS tagOptionId, opt.option_name AS optionName, r.pass_result AS passResult, r.annotated_at AS annotatedAt FROM t_eval_task_tag_result r JOIN t_eval_task_tag tt ON r.task_tag_id = tt.id JOIN t_eval_tag tag ON tt.tag_id = tag.id LEFT JOIN t_eval_tag_option opt ON r.tag_option_id = opt.id WHERE r.task_item_id IN
#{taskItemId}
ORDER BY tt.display_order ASC
